INSERT INTO categories (id, name, slug, description, seo_title, seo_description, status, sort_order)
VALUES
  (4, 'Conversion', 'conversion', 'Unit conversion calculators for length, weight, and temperature.', 'Conversion Calculators | Length, Weight and Temperature', 'Convert common units online with simple conversion calculators.', 'published', 4),
  (5, 'Date & Time', 'date-time', 'Date and time calculators for ages, date differences, and work duration estimates.', 'Date and Time Calculators | Age, Duration and Date Difference', 'Calculate ages, date differences, and time durations with free online tools.', 'published', 5);
INSERT INTO calculators (id, category_id, name, slug, short_description, long_description, h1_title, intro_content, how_to_use, formula_explanation, examples_content, notes_content, formula_type, formula_config_json, status, sort_order)
VALUES
  (104, 2, 'Unit Price Calculator', 'unit-price-calculator', 'Compare prices by calculating cost per unit.', 'Compare packages and bulk purchases with a cost-per-unit value.', 'Unit Price Calculator', 'Enter total price and quantity to find price per unit.', 'Enter price; Enter quantity; Compare unit price', 'Unit price = total price / quantity.', '$18 for 12 items equals $1.50 per item.', 'Use the same unit type when comparing products.', 'unit_price', '{}', 'published', 4),
  (105, 2, 'Compound Interest Calculator', 'compound-interest-calculator', 'Estimate future value and interest earned over time.', 'Estimate how an initial principal grows with repeated compounding.', 'Compound Interest Calculator', 'Enter principal, annual rate, years, and compounding frequency.', 'Enter principal; Enter rate; Choose term and compounding', 'Future value = principal x (1 + rate / n)^(n x years).', '$10,000 at 5% monthly for 10 years grows to about $16,470.09.', 'Does not include taxes, fees, inflation, or added contributions.', 'compound_interest', '{}', 'published', 5),
  (106, 2, 'Mortgage Calculator', 'mortgage-calculator', 'Estimate mortgage principal, interest, and monthly housing costs.', 'Estimate loan amount, principal and interest payment, monthly total, and total interest.', 'Mortgage Calculator', 'Enter home price, down payment, rate, term, and monthly costs.', 'Enter home price; Enter loan terms; Add monthly costs', 'Mortgage payment uses the fixed-rate amortization formula.', '$400,000 with $80,000 down at 6.75% over 30 years has about $2,075 principal and interest.', 'Does not include HOA, PMI, closing costs, or rate changes.', 'mortgage_payment', '{}', 'published', 6),
  (107, 3, 'Tip Calculator', 'tip-calculator', 'Calculate tip amount, total bill, and split cost per person.', 'Estimate gratuity, total cost, and per-person split for a bill.', 'Tip Calculator', 'Enter bill amount, tip percentage, and number of people.', 'Enter bill; Enter tip; Enter people', 'Tip = bill x tip percent / 100. Per person = total / people.', '$80 with an 18% tip is $94.40 total.', 'Local tipping customs and service charges can vary.', 'tip', '{}', 'published', 7),
  (108, 3, 'Discount Calculator', 'discount-calculator', 'Calculate sale price, discount amount, and optional tax.', 'Find savings from a percentage discount and estimate final price after tax.', 'Discount Calculator', 'Enter original price, discount percentage, and tax rate.', 'Enter price; Enter discount; Add tax', 'Discount amount = original price x discount percentage / 100.', '25% off $120 saves $30.', 'Stores may apply coupons and taxes in different orders.', 'discount', '{}', 'published', 8),
  (109, 3, 'Sales Tax Calculator', 'sales-tax-calculator', 'Calculate tax amount and total price after tax.', 'Estimate tax amount and final price from purchase amount and tax rate.', 'Sales Tax Calculator', 'Enter a price and tax rate to estimate total after tax.', 'Enter price; Enter tax rate; Review total', 'Tax amount = price x tax rate / 100.', '$50 at 8.25% adds $4.13 tax.', 'Tax rules vary by location, product, and exemption.', 'sales_tax', '{}', 'published', 9),
  (110, 2, 'Savings Goal Calculator', 'savings-goal-calculator', 'Estimate how long it takes to reach a savings goal.', 'Estimate remaining amount, months to goal, and years to goal.', 'Savings Goal Calculator', 'Enter goal amount, current savings, and monthly contribution.', 'Enter goal; Enter current savings; Enter monthly contribution', 'Months to goal = remaining amount / monthly contribution.', '$500 per month toward a $12,000 goal from $2,000 saved takes 20 months.', 'Does not include interest, fees, or market returns.', 'savings_goal', '{}', 'published', 10),
  (111, 1, 'Calorie Calculator', 'calorie-calculator', 'Estimate BMR, maintenance calories, and a simple deficit target.', 'Estimate basal metabolic rate and daily maintenance calories.', 'Calorie Calculator', 'Enter body details and activity level to estimate daily calorie needs.', 'Enter body details; Choose activity; Review calories', 'BMR uses the Mifflin-St Jeor equation.', 'A moderately active 70 kg male can estimate maintenance calories.', 'Calorie estimates are rough planning tools.', 'calorie', '{}', 'published', 11),
  (112, 1, 'Body Fat Calculator', 'body-fat-calculator', 'Estimate body fat percentage using circumference measurements.', 'Use the US Navy circumference method for a body fat estimate.', 'Body Fat Calculator', 'Enter circumference measurements in centimeters.', 'Choose gender; Enter measurements; Review estimate', 'Uses US Navy circumference equations after converting centimeters to inches.', 'A male with 86 cm waist and 39 cm neck can estimate body fat.', 'This differs from DEXA, calipers, or other methods.', 'body_fat', '{}', 'published', 12),
  (113, 1, 'Pace Calculator', 'pace-calculator', 'Calculate running pace, total minutes, and speed.', 'Estimate minutes per mile and miles per hour from distance and finish time.', 'Pace Calculator', 'Enter distance and time to calculate pace and speed.', 'Enter distance; Enter time; Review pace', 'Pace = total minutes / distance. Speed = distance / hours.', '6.2 miles in 50 minutes is about 8.06 minutes per mile.', 'This version uses miles.', 'pace', '{}', 'published', 13),
  (114, 5, 'Age Calculator', 'age-calculator', 'Calculate age in years, months, and total months.', 'Estimate age from a birth date to a selected as-of date.', 'Age Calculator', 'Enter birth date and as-of date to calculate age.', 'Enter birth date; Enter as-of date; Review age', 'Age compares full calendar years and months between two dates.', '1990-01-15 to 2026-04-12 is 36 years and 2 months.', 'Uses UTC date construction to avoid time zone drift.', 'age', '{}', 'published', 14),
  (115, 5, 'Date Difference Calculator', 'date-difference-calculator', 'Calculate days, weeks, and approximate months between two dates.', 'Count days between a start date and an end date.', 'Date Difference Calculator', 'Enter two dates to calculate the difference.', 'Enter start date; Enter end date; Review difference', 'Days are calculated from UTC timestamps.', '2026-01-01 to 2026-04-12 is 101 days.', 'Approximate months use 30.4375 days.', 'date_difference', '{}', 'published', 15),
  (116, 5, 'Time Duration Calculator', 'time-duration-calculator', 'Calculate elapsed time between two 24-hour times.', 'Estimate minutes and decimal hours between a start and end time.', 'Time Duration Calculator', 'Enter start time, end time, and break minutes.', 'Enter start; Enter end; Subtract break', 'Duration minutes = end time - start time - break minutes.', '9:00 to 17:30 with 30-minute break is 8 hours.', 'Use 24-hour time.', 'time_duration', '{}', 'published', 16),
  (117, 4, 'Length Converter', 'length-converter', 'Convert between common length and distance units.', 'Convert millimeters, centimeters, meters, kilometers, inches, feet, yards, and miles.', 'Length Converter', 'Enter a value and choose units to convert length.', 'Enter value; Choose from unit; Choose to unit', 'Converts source value to meters, then to target unit.', '10 kilometers equals about 6.21 miles.', 'Uses standard international conversion factors.', 'length_conversion', '{}', 'published', 17),
  (118, 4, 'Weight Converter', 'weight-converter', 'Convert between grams, kilograms, ounces, pounds, and tons.', 'Convert common metric and US customary weight units.', 'Weight Converter', 'Enter a value and select units to convert weight.', 'Enter value; Choose from unit; Choose to unit', 'Converts source value to kilograms, then to target unit.', '10 kilograms equals about 22.05 pounds.', 'The ton option uses the US short ton.', 'weight_conversion', '{}', 'published', 18),
  (119, 4, 'Temperature Converter', 'temperature-converter', 'Convert Celsius, Fahrenheit, and Kelvin.', 'Convert values between Celsius, Fahrenheit, and Kelvin.', 'Temperature Converter', 'Enter a temperature and choose source and target units.', 'Enter value; Choose from unit; Choose to unit', 'Converts source temperature to Celsius, then to target unit.', '68 degrees Fahrenheit equals 20 degrees Celsius.', 'Kelvin values below absolute zero are not physically meaningful.', 'temperature_conversion', '{}', 'published', 19),
  (120, 2, 'Fuel Cost Calculator', 'fuel-cost-calculator', 'Estimate fuel needed, trip cost, and cost per mile.', 'Estimate gallons needed, total fuel cost, and cost per mile.', 'Fuel Cost Calculator', 'Enter distance, MPG, and price per gallon to estimate fuel cost.', 'Enter distance; Enter MPG; Enter fuel price', 'Gallons needed = distance / MPG. Total fuel cost = gallons x price.', '300 miles at 30 MPG and $3.50 per gallon costs about $35.', 'Actual cost varies with traffic, terrain, and fuel price.', 'fuel_cost', '{}', 'published', 20);
