INSERT INTO calculator_faqs (calculator_id, question, answer, sort_order)
VALUES
  (104, 'What is unit price?', 'Unit price is the cost for one unit of a product.', 1),
  (104, 'Why compare unit prices?', 'It makes different package sizes easier to compare.', 2),
  (105, 'What does compounding mean?', 'Compounding means interest is added to the balance and future interest is calculated on that larger balance.', 1),
  (105, 'Does this include contributions?', 'No. This estimate uses one starting principal.', 2),
  (106, 'Does this include PMI?', 'No. Add PMI separately if it applies.', 1),
  (106, 'Why include tax and insurance?', 'They are common monthly housing costs and make the total more realistic.', 2),
  (107, 'Can I split the bill?', 'Yes. Enter the number of people and the total is divided evenly.', 1),
  (107, 'Does this include tax?', 'It uses the bill amount you enter.', 2),
  (108, 'Can I enter zero tax?', 'Yes. Enter 0 for a pre-tax sale price only.', 1),
  (108, 'What is the sale price formula?', 'Sale price is original price minus the discount amount.', 2),
  (109, 'Does this support tax-inclusive pricing?', 'No. This assumes the entered price is before tax.', 1),
  (109, 'Can I use any tax rate?', 'Yes. Enter the rate that applies to your location or purchase.', 2),
  (110, 'Does this include interest?', 'No. It estimates a straight-line timeline from monthly contributions.', 1),
  (110, 'What if I already reached the goal?', 'The remaining amount becomes zero and the timeline shows zero months.', 2),
  (111, 'What is BMR?', 'BMR is an estimate of calories your body uses at rest.', 1),
  (111, 'Is the deficit target safe for everyone?', 'No. Calorie targets should be personalized.', 2),
  (112, 'Is hip measurement required?', 'It is required for the female US Navy estimate.', 1),
  (112, 'How accurate is this method?', 'It is a convenient estimate and depends on measurement consistency.', 2),
  (113, 'Can I use kilometers?', 'This version labels distance as miles, so convert kilometers first.', 1),
  (113, 'What does pace mean?', 'Pace is the time it takes to cover one distance unit.', 2),
  (114, 'Does this use today automatically?', 'This demo uses an editable as-of date for predictable results.', 1),
  (114, 'Why are days not shown?', 'The current result focuses on years and months.', 2),
  (115, 'Are dates inclusive?', 'The result is elapsed difference between timestamps, not an inclusive calendar count.', 1),
  (115, 'Why are months approximate?', 'Months have different lengths, so this uses the average month length.', 2),
  (116, 'Does it support overnight shifts?', 'Yes. If end time is earlier, it treats the end as the next day.', 1),
  (116, 'Can break time be zero?', 'Yes. Enter 0 if no break should be subtracted.', 2),
  (117, 'Which units are supported?', 'Millimeters, centimeters, meters, kilometers, inches, feet, yards, and miles are supported.', 1),
  (117, 'Can I convert negative values?', 'Yes, if you intentionally need a signed length value.', 2),
  (118, 'What ton does this use?', 'It uses the US short ton of 2,000 pounds.', 1),
  (118, 'Does this convert force?', 'No. This is an everyday mass and weight unit converter.', 2),
  (119, 'Does this support Kelvin?', 'Yes. You can convert to and from Kelvin.', 1),
  (119, 'What is 68 degrees Fahrenheit in Celsius?', '68 degrees Fahrenheit is 20 degrees Celsius.', 2),
  (120, 'Does this work for electric vehicles?', 'No. This version is for MPG and price per gallon.', 1),
  (120, 'Should I use highway or city MPG?', 'Use the MPG that best matches expected driving conditions.', 2);
INSERT INTO seo_meta (ref_type, ref_id, meta_title, meta_description, canonical_url, robots)
VALUES
  ('calculator', 104, 'Unit Price Calculator - Compare Cost Per Unit', 'Find cost per unit for groceries, bulk purchases, and everyday price comparisons.', '/calculator/unit-price-calculator', 'index,follow'),
  ('calculator', 105, 'Compound Interest Calculator - Future Value Estimate', 'Estimate compound interest, future value, and interest earned over time.', '/calculator/compound-interest-calculator', 'index,follow'),
  ('calculator', 106, 'Mortgage Calculator - Estimate Monthly House Payment', 'Estimate mortgage payment, loan amount, monthly housing cost, and total interest.', '/calculator/mortgage-calculator', 'index,follow'),
  ('calculator', 107, 'Tip Calculator - Split Bill and Tip Amount', 'Calculate tip amount, total bill, and per-person split with a free tip calculator.', '/calculator/tip-calculator', 'index,follow'),
  ('calculator', 108, 'Discount Calculator - Sale Price and Savings', 'Find discount amount, sale price, and after-tax total from an original price and discount percent.', '/calculator/discount-calculator', 'index,follow'),
  ('calculator', 109, 'Sales Tax Calculator - Tax Amount and Total Price', 'Calculate sales tax amount and final price after tax from a price and tax rate.', '/calculator/sales-tax-calculator', 'index,follow'),
  ('calculator', 110, 'Savings Goal Calculator - Months to Reach a Goal', 'Estimate how many months and years it takes to reach a savings goal.', '/calculator/savings-goal-calculator', 'index,follow'),
  ('calculator', 111, 'Calorie Calculator - Estimate Daily Calorie Needs', 'Estimate BMR, maintenance calories, and a simple calorie deficit target.', '/calculator/calorie-calculator', 'index,follow'),
  ('calculator', 112, 'Body Fat Calculator - Estimate Body Fat Percentage', 'Estimate body fat percentage from waist, neck, height, and hip measurements.', '/calculator/body-fat-calculator', 'index,follow'),
  ('calculator', 113, 'Pace Calculator - Running Pace and Speed', 'Calculate running pace, total minutes, and speed from distance and finish time.', '/calculator/pace-calculator', 'index,follow'),
  ('calculator', 114, 'Age Calculator - Calculate Age in Years and Months', 'Calculate age from birth date to a selected date in years, months, and total months.', '/calculator/age-calculator', 'index,follow'),
  ('calculator', 115, 'Date Difference Calculator - Days Between Dates', 'Calculate days, weeks, and approximate months between two dates.', '/calculator/date-difference-calculator', 'index,follow'),
  ('calculator', 116, 'Time Duration Calculator - Hours Between Times', 'Calculate elapsed minutes and hours between two 24-hour times with optional break time.', '/calculator/time-duration-calculator', 'index,follow'),
